#!/bin/bash
set -e
if echo dGVzdA== | base64 -D >/dev/null 2>&1; then B64FLAG="-D"; else B64FLAG="-d"; fi
mkdir -p components
echo 'Writing components/Nav.js...'
base64 $B64FLAG << 'B64_HIDE_1' > components/Nav.js

B64_HIDE_1
echo 'Writing components/Footer.js...'
base64 $B64FLAG << 'B64_HIDE_2' > components/Footer.js

B64_HIDE_2
echo 'Gallery link hidden from Nav and Footer.'
